private createJob(mode: CronJobRecord['mode'], schedule: string, options: ScheduleOptions): string {
  const id = nanoid()
  const record = this.buildRecord(id, mode, schedule, options)
  this.store.save(record)
  this.scheduleJob(record)
  return id
}

at(date: Date | string, options: ScheduleOptions): string {
  const schedule = date instanceof Date ? date.toISOString() : date
  return this.createJob('at', schedule, options)
}

every(intervalSeconds: number, options: ScheduleOptions): string {
  return this.createJob('every', String(intervalSeconds), options)
}

cron(expression: string, options: ScheduleOptions): string {
  return this.createJob('cron', expression, options)
}

WHY: Extracts the shared 4-line sequence (nanoid + buildRecord + save + schedule + return) into a single private method. The public methods become thin type-safe adapters that normalize input and delegate. Reduces duplication from 21 lines to 12 while preserving the clear public API.

