AFTER:
const { pattern, opts } = this.cronArgsForMode(record, cronOptions)
const cronJob = new Cron(pattern, opts, callback)

// New private method:
private cronArgsForMode(record: CronJobRecord, baseOptions: Record<string, unknown>) {
  switch (record.mode) {
    case 'at':    return { pattern: new Date(record.schedule), opts: baseOptions }
    case 'every': return { pattern: '* * * * * *', opts: { ...baseOptions, interval: Number(record.schedule) } }
    case 'cron':  return { pattern: record.schedule, opts: baseOptions }
  }
}

WHY: Isolates the mode-specific logic into a pure mapping function, allowing scheduleJob() to remain a simple linear flow. The switch itself stays (it is the right tool for 3 exhaustive cases) but lives in its own method with a single responsibility. This is a minor clarity improvement -- optional.
